<Stats id="monster-ghole--stats" atts={[25,18,21,10,17,16]} bab={16} cmb={23} cmd={37} feats={["Cleave","Combat Reflexes","Great Cleave","Great Fortitude",["Improved Critical"," (bite, claw)"],"Improved Initiative","Power Attack"]} skills={{"per":{"b":22}}} lang={["C"]} sq={<><Link to="/umr/change_shape">change shape</Link> (Medium humanoid; <Link to="/spell/alter_self">alter self</Link>)</>} />
